import{_ as e,j as i,o as t,v as l}from"./chunks/framework.OlxNbC8G.js";const a=JSON.parse('{"title":"Chào mọi người 😃","description":"","frontmatter":{"footer":true,"outline":"deep","date":"2024-02-22T00:00:00.000Z"},"headers":[{"level":1,"title":"Chào mọi người 😃","slug":"chao-moi-nguoi","link":"#chao-moi-nguoi","children":[]},{"level":1,"title":"Mục tiêu","slug":"muc-tieu","link":"#muc-tieu","children":[{"level":2,"title":"1. Internet","slug":"_1-internet","link":"#_1-internet","children":[]},{"level":2,"title":"2. Relational Databases(RDBMS)","slug":"_2-relational-databases-rdbms","link":"#_2-relational-databases-rdbms","children":[{"level":3,"title":"2.1 PostgreSQL","slug":"_2-1-postgresql","link":"#_2-1-postgresql","children":[{"level":4,"title":"2.1.1 RDBMS Concepts","slug":"_2-1-1-rdbms-concepts","link":"#_2-1-1-rdbms-concepts","children":[]}]},{"level":3,"title":"3 : API","slug":"_3-api","link":"#_3-api","children":[]},{"level":3,"title":"4 : Caching","slug":"_4-caching","link":"#_4-caching","children":[]},{"level":3,"title":"5. Web Security Knowledge","slug":"_5-web-security-knowledge","link":"#_5-web-security-knowledge","children":[]}]}]}],"relativePath":"study/thanhlv-study-2024/gioi-thieu-ve-muc-tieu-hoc-tap-be-nam-2024-cua-thanh-lv.md","filePath":"study/thanhlv-study-2024/gioi-thieu-ve-muc-tieu-hoc-tap-be-nam-2024-cua-thanh-lv.md","lastUpdated":1709179603000}'),n={name:"study/thanhlv-study-2024/gioi-thieu-ve-muc-tieu-hoc-tap-be-nam-2024-cua-thanh-lv.md"},r=[l('<h1 id="chao-moi-nguoi" tabindex="-1">Chào mọi người 😃 <a class="header-anchor" href="#chao-moi-nguoi" aria-label="Permalink to &quot;Chào mọi người :)&quot;">​</a></h1><p>Xin chào mọi người 😃</p><p>Đây là sẽ là nơi chứa note của mình cho học tập các kiến thức mới về công nghệ BE năm 2024.</p><h1 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h1><h2 id="_1-internet" tabindex="-1">1. Internet <a class="header-anchor" href="#_1-internet" aria-label="Permalink to &quot;1. Internet&quot;">​</a></h2><p>Hiện tại tất các ứng dụng đều sẽ được phát hành trên Internet, vì vậy tìm hiểu về Internet là một điều cần thiết để biết cách Internet hoạt động trên trái đất 😃.</p><ol><li>Internet hoạt động như thế nào?</li><li>HTTP là gì ?</li><li>Làm cách nào để Browsers hoạt động ?</li><li>Domain Name là gì ? Làm cách nào để nó hoạt động ?</li><li>DNS là gì ? làm cách nào để nó nó hoạt động ?</li></ol><h2 id="_2-relational-databases-rdbms" tabindex="-1">2. Relational Databases(RDBMS) <a class="header-anchor" href="#_2-relational-databases-rdbms" aria-label="Permalink to &quot;2. Relational Databases(RDBMS)&quot;">​</a></h2><p>Cơ sở dữ liệu là một thức rất quan trọng, nó sử dụng để lưu trữ các dữ liệu của doanh nghiệp và ứng dụng của chúng ta.</p><p>Vì vậy tôi muốn học lại các kiến thức cơ bản về nó</p><ol><li>Database là gì ?</li><li>Relational Databases là gì ?</li><li>Lợi ích và hạn chế của RDBMS(<code>Relational Database Management System</code>)</li></ol><h3 id="_2-1-postgresql" tabindex="-1">2.1 PostgreSQL <a class="header-anchor" href="#_2-1-postgresql" aria-label="Permalink to &quot;2.1 PostgreSQL&quot;">​</a></h3><p>Trong 1 vài năm gây đây tôi thấy PostgreSQL đang khá nổi và được sử dụng nhiều. Vì vậy tôi quyết định học nó.</p><p>Tất nhiên là tôi không phải DBA, vì vậy tôi sẽ chỉ học ở mức độ cơ bản sau đó sẽ ưu tiên học các phần quan trọng khác.</p><ol><li>Vì sao là PostgreSQL ?</li><li>Học cách cài đặt PostgreSQL. <ol><li>cài đặt trên máy chủ vật lý.( Cài đặt thử cả cluster )</li><li>Cài đặt sử dụng docker image.( Cài đặt thử cả cluster )</li></ol></li></ol><h4 id="_2-1-1-rdbms-concepts" tabindex="-1">2.1.1 RDBMS Concepts <a class="header-anchor" href="#_2-1-1-rdbms-concepts" aria-label="Permalink to &quot;2.1.1 RDBMS Concepts&quot;">​</a></h4><ol><li>Các Data Types</li><li>Schemas là gì ?</li><li>Domains là gì ?</li><li>Attributes là gì ?</li><li>Các Constraints.</li><li>ACID</li><li>Multi-Version Concurrency Control (MVCC in PostgreSQL)</li><li>Transactions</li><li>N plus one problem</li><li>Database Normalization</li><li>Failure Modes</li><li>Profiling Performance</li></ol><h3 id="_3-api" tabindex="-1">3 : API <a class="header-anchor" href="#_3-api" aria-label="Permalink to &quot;3 : API&quot;">​</a></h3><ul><li><a href="https://jsonapi.org/" target="_blank" rel="noreferrer">https://jsonapi.org/</a></li></ul><h3 id="_4-caching" tabindex="-1">4 : Caching <a class="header-anchor" href="#_4-caching" aria-label="Permalink to &quot;4 : Caching&quot;">​</a></h3><ul><li>Client Side Caching</li><li>Server side <ul><li>Redis</li><li>Memcached</li></ul></li><li>CDN (Content Delivery Network)</li></ul><h3 id="_5-web-security-knowledge" tabindex="-1">5. Web Security Knowledge <a class="header-anchor" href="#_5-web-security-knowledge" aria-label="Permalink to &quot;5. Web Security Knowledge&quot;">​</a></h3><ul><li>Dự án <code>OWASP Security Risks</code>: <a href="https://cheatsheetseries.owasp.org/index.html" target="_blank" rel="noreferrer">https://cheatsheetseries.owasp.org/index.html</a></li><li>Content Security Policy</li><li>Server Security</li></ul>',23)];const o=e(n,[["render",function(e,l,a,n,o,c){return t(),i("div",null,r)}]]);export{a as __pageData,o as default};
